import{_ as e,o,c as a,ai as r}from"./chunks/framework.DMjte4z8.js";const h=JSON.parse('{"title":"JASS入门：从T触发翻译到代码","description":"","frontmatter":{"title":"JASS入门：从T触发翻译到代码","category":"scripting","updated":"2026-05-21T00:00:00.000Z","model":"openai/MiniMax-M2.7-highspeed","quality_score":0.72,"discovered_via":"gap_finder","sources":["https://www.hiveworkshop.com/threads/ever-wanted-to-run-jass-scripts-outside-of-war3.266101/","https://deepwiki.com/qq1792569310/demodemodemodemo/2.3-jass-native-hooking","https://3gstudent.github.io/backup-3gstudent.github.io/War3地图-漏洞-分析介绍/","https://nextgenupdate.com/forums/pc-amp-steam-gaming/221496-basic-tutorialthe-warcraft-three-world-editor-1.html","https://www.3ice.hu/blog/protect-warcraft-maps/"]},"headers":[],"relativePath":"scripting/jass入门从t触发翻译到代码.md","filePath":"scripting/jass入门从t触发翻译到代码.md","lastUpdated":1779353774000}'),s={name:"scripting/jass入门从t触发翻译到代码.md"};function i(l,t,n,d,c,p){return o(),a("div",null,[...t[0]||(t[0]=[r(`<h1 id="jass入门-从t触发翻译到代码" tabindex="-1">JASS入门：从T触发翻译到代码 <a class="header-anchor" href="#jass入门-从t触发翻译到代码" aria-label="Permalink to “JASS入门：从T触发翻译到代码”">​</a></h1><h2 id="jass简介-什么是jass以及为什么要学习它" tabindex="-1">JASS简介：什么是JASS以及为什么要学习它 <a class="header-anchor" href="#jass简介-什么是jass以及为什么要学习它" aria-label="Permalink to “JASS简介：什么是JASS以及为什么要学习它”">​</a></h2><p>在本节中，你将了解什么是JASS语言，它在魔兽争霸3地图中扮演什么角色，以及何时应该选择使用JASS而不是图形触发器。读完本节后，你就能明白为什么有些功能只有通过代码才能实现。</p><h3 id="什么是jass" tabindex="-1">什么是JASS <a class="header-anchor" href="#什么是jass" aria-label="Permalink to “什么是JASS”">​</a></h3><p><strong>JASS</strong> 是《魔兽争霸3》的脚本编程语言，全称是 &quot;Julnerability and Assault Scripting System&quot;（也有说法只是&quot;JASS&quot;本身）。简单来说，JASS就是控制地图运行逻辑的&quot;幕后指挥官&quot;——从单位移动、技能释放、伤害计算，到游戏胜负判定，一切都在JASS的掌控之中[^3]。</p><p>打个比方：如果你的地图是一座房子，那么JASS就是房子里的电线和水管，看不见摸不着，但房间里的每一盏灯、每一个水龙头都要靠它才能工作。</p><h3 id="图形触发器-gui-与jass代码的区别" tabindex="-1">图形触发器（GUI）与JASS代码的区别 <a class="header-anchor" href="#图形触发器-gui-与jass代码的区别" aria-label="Permalink to “图形触发器（GUI）与JASS代码的区别”">​</a></h3><p>你之前使用的&quot;T触发器&quot;（也称为&quot;图形触发器&quot;或GUI触发器），实际上是JASS的&quot;可视化翻译版本&quot;——你在编辑器里点的每一个按钮、拉的每一条线，World Editor都会在背后自动生成对应的JASS代码。</p><table tabindex="0"><thead><tr><th>对比项</th><th>图形触发器（GUI）</th><th>JASS代码</th></tr></thead><tbody><tr><td>操作方式</td><td>拖拽、点击、选择</td><td>手动输入代码</td></tr><tr><td>学习难度</td><td>较低</td><td>较高</td></tr><tr><td>功能上限</td><td>受编辑器限制</td><td>几乎无限制</td></tr><tr><td>执行效率</td><td>稍低</td><td>更高</td></tr><tr><td>可读性</td><td>直观</td><td>需要学习语法</td></tr></tbody></table><blockquote><p><strong>💡 新手提示</strong>：每次你在图形触发器里保存时，编辑器其实都在后台&quot;翻译&quot;成JASS代码。如果你想看编辑器给你写了什么，可以右键触发器选择&quot;转换为自定义代码&quot;查看（但请勿随意修改！）</p></blockquote><h3 id="什么时候需要使用jass" tabindex="-1">什么时候需要使用JASS <a class="header-anchor" href="#什么时候需要使用jass" aria-label="Permalink to “什么时候需要使用JASS”">​</a></h3><p>以下几种情况，你需要考虑学习JASS：</p><ol><li><strong>需要精细控制游戏逻辑</strong>：比如编写复杂的AI判断、动态难度调整、多线程同时执行多个操作</li><li><strong>图形触发器做不到的功能</strong>：某些高级功能（如修改游戏底层机制、拦截调用魔兽内置函数等）必须通过JASS实现[^2]</li><li><strong>性能优化</strong>：大量单位同时触发事件时，JASS代码比图形触发器执行效率更高</li><li><strong>保护地图</strong>：使用JASS可以实现更高级的地图加密保护[^5]</li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手一听说JASS很厉害，就想跳过图形触发器直接学代码。这是错误的学习路径！图形触发器是你理解游戏逻辑的基石，建议至少熟练使用T触发器1-2个月后，再开始接触JASS。</p></blockquote><h3 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to “小结”">​</a></h3><p>现在你应该明白：<strong>JASS是魔兽争霸3地图的底层编程语言</strong>，而你之前使用的图形触发器只是它的一个&quot;可视化界面&quot;。学习JASS不是为了替代图形触发器，而是为了突破图形触发器的功能上限，实现更强大的地图效果。本教程后续章节将手把手教你如何将图形触发器&quot;翻译&quot;成JASS代码，从简单的阅读开始，逐步掌握编写能力。</p><h2 id="触发器编辑器基础概念" tabindex="-1">触发器编辑器基础概念 <a class="header-anchor" href="#触发器编辑器基础概念" aria-label="Permalink to “触发器编辑器基础概念”">​</a></h2><p>本节将带你认识触发器编辑器的核心概念，学会查看触发器的JASS代码，并亲手创建第一个简单触发器。学完本节后，你就能理解触发器是如何&quot;指挥&quot;游戏运行的。</p><h3 id="触发器的三个核心部分-事件、条件、动作" tabindex="-1">触发器的三个核心部分：事件、条件、动作 <a class="header-anchor" href="#触发器的三个核心部分-事件、条件、动作" aria-label="Permalink to “触发器的三个核心部分：事件、条件、动作”">​</a></h3><p>触发器（Trigger）是魔兽争霸3地图中控制游戏逻辑的核心工具。你可以把它想象成一张&quot;如果...那么...&quot;的指令卡[^3]。</p><p>触发器由三个核心部分组成：</p><ol><li><strong>事件（Event）</strong> — 触发器被激活的&quot;开关&quot;，比如&quot;单位死亡&quot;、&quot;玩家输入文字&quot;、&quot;游戏开始&quot;等[^4]</li><li><strong>条件（Condition）</strong> — 判断是否要执行动作的&quot;过滤器&quot;，只有满足条件才会继续</li><li><strong>动作（Action）</strong> — 当事件发生且条件满足时，真正执行的操作，比如&quot;显示消息&quot;、&quot;创建单位&quot;、&quot;改变生命值&quot;等</li></ol><h3 id="在编辑器中查看触发器的jass代码" tabindex="-1">在编辑器中查看触发器的JASS代码 <a class="header-anchor" href="#在编辑器中查看触发器的jass代码" aria-label="Permalink to “在编辑器中查看触发器的JASS代码”">​</a></h3><p>触发器编辑器以可视化界面呈现逻辑，但底层运行的其实是JASS代码[^3]。了解这一点对学习JASS很重要。</p><ol><li><strong>第一步：打开触发器编辑器</strong> — 在World Editor中点击顶部菜单的&quot;触发器编辑器&quot;按钮[^4]</li><li><strong>第二步：选择一个触发器</strong> — 在左侧列表中点击任意一个已存在的触发器</li><li><strong>第三步：查看代码</strong> — 点击菜单&quot;编辑&quot;→&quot;将触发器复制为文本&quot;（或使用快捷键Ctrl+Shift+C），你会看到JASS代码</li></ol><blockquote><p><strong>💡 新手提示</strong>：初学者不需要完全读懂这些代码，只需记住：触发器编辑器的每一个可视化操作，背后都对应一行JASS代码。</p></blockquote><h3 id="简单触发器的创建与调试" tabindex="-1">简单触发器的创建与调试 <a class="header-anchor" href="#简单触发器的创建与调试" aria-label="Permalink to “简单触发器的创建与调试”">​</a></h3><p>让我们创建你的第一个触发器：</p><ol><li><strong>第一步：新建触发器</strong> — 在触发器编辑器左侧空白处右键，选择&quot;新建触发器&quot;，给它起名如&quot;MyFirstTrigger&quot;[^4]</li><li><strong>第二步：添加事件</strong> — 右键点击触发器，选择&quot;新建事件&quot;，然后选择&quot;游戏 - 游戏开始&quot;</li><li><strong>第三步：添加动作</strong> — 右键选择&quot;新建动作&quot;，选择&quot;游戏 - 显示标题屏幕消息&quot;，输入任意文字</li><li><strong>第四步：测试地图</strong> — 保存地图（Ctrl+S），按F9测试游戏，你应该在开局时看到你输入的文字</li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：新手常忘记保存地图就测试，导致修改没有生效。每次修改后务必记得Ctrl+S保存！</p></blockquote><h3 id="小结-1" tabindex="-1">小结 <a class="header-anchor" href="#小结-1" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你应该已经理解了触发器&quot;事件→条件→动作&quot;的工作流程，能够在触发器编辑器中查看JASS代码，并成功创建了一个简单的触发器。这些基础将为你后续学习JASS编程打下坚实基础。</p><h2 id="jass基础语法入门" tabindex="-1">JASS基础语法入门 <a class="header-anchor" href="#jass基础语法入门" aria-label="Permalink to “JASS基础语法入门”">​</a></h2><p>本节将带你认识JASS最核心的三个概念：<strong>变量、数据类型、函数和注释</strong>。学完本节后，你将能够读懂一段简单的JASS代码，并写出自己的第一条声明语句。</p><h3 id="操作步骤" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤" aria-label="Permalink to “操作步骤”">​</a></h3><ol><li><p><strong>第一步：理解什么是变量</strong> — 变量就像一个<strong>贴了标签的盒子</strong>，用来存放数据。在JASS中，每个变量都有一个名字，比如 <code>hp</code> 代表生命值，<code>name</code> 代表角色名字[^3]。世界编辑器打开地图后，在触发编辑器里就能创建这些变量。</p></li><li><p><strong>第二步：学习JASS的基本数据类型</strong> — JASS里最常用的数据类型有三种：</p><ul><li><code>integer</code>（整数）：用来表示1、2、100这样的整数值</li><li><code>real</code>（实数）：用来表示带小数的数字，如3.14</li><li><code>string</code>（字符串）：用来表示文字，如&quot;你好&quot;[^3]</li></ul><p>在触发编辑器中新建变量时，选择变量类型下拉菜单就能看到这些选项。</p></li><li><p><strong>第三步：变量声明的基本格式</strong> — JASS中声明变量的写法是 <code>local 类型 变量名</code>，比如：</p><div class="language-jass line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">jass</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>local integer hp</span></span>
<span class="line"><span>local real speed</span></span>
<span class="line"><span>local string hero_name</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>注意：每行语句末尾<strong>必须加分号</strong> <code>;</code>，这是新手最容易忘记的地方。</p></li><li><p><strong>第四步：了解函数是什么</strong> — 函数是一段<strong>可以反复使用的代码</strong>，就像一个预设好的小工具。世界编辑器中内置了很多&quot;原生函数&quot;（Native），比如 <code>SetUnitHP()</code> 用来设置生命值[^2]。你可以直接调用它们。</p></li><li><p><strong>第五步：函数调用的写法</strong> — 调用函数时，用 <code>call 函数名(参数1, 参数2)</code> 的格式。比如：</p><div class="language-jass line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">jass</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>call SetUnitHP(gg_unit_Hero_001, 500)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这句代码的意思是：把英雄的生命值设置为500。</p></li><li><p><strong>第六步：学会写注释</strong> — 注释是给人类看的说明文字，电脑会自动忽略。JASS中用 <code>//</code> 开头写单行注释，比如：</p><div class="language-jass line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">jass</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>// 这是设置英雄生命值的代码</span></span>
<span class="line"><span>call SetUnitHP(gg_unit_Hero_001, 500) // 生命值设为500</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>养成写注释的习惯，能让你的代码几个月后再看也能看懂。</p></li></ol><blockquote><p><strong>💡 新手提示</strong>：在触发编辑器里点击&quot;编辑&quot;→&quot;转换为JASS&quot;，就能看到当前触发器对应的JASS代码。多观察这些自动生成的代码，是学习JASS的好方法。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手把变量名写成中文或带空格，比如 <code>local integer 我的血量</code> 是<strong>错误</strong>的。JASS只认英文变量名，且不能有空格，必须是连续的字母数字组合（如 <code>hero_hp</code>）。</p></blockquote><h3 id="小结-2" tabindex="-1">小结 <a class="header-anchor" href="#小结-2" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你应该能看懂这样的简单JASS代码：</p><div class="language-jass line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">jass</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>local integer hp</span></span>
<span class="line"><span>set hp = 100</span></span>
<span class="line"><span>call DisplayTextToPlayer(Player(0), 0, 0, &quot;英雄出生了！&quot;)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>如果看不懂也没关系，下一节我们将深入讲解触发器与JASS的对应关系，带你一步步把&quot;鼠标操作&quot;翻译成代码。</p><h2 id="从t触发到jass代码的转换方法" tabindex="-1">从T触发到JASS代码的转换方法 <a class="header-anchor" href="#从t触发到jass代码的转换方法" aria-label="Permalink to “从T触发到JASS代码的转换方法”">​</a></h2><p>本节将教你如何把在触发编辑器（T触发）中创建的触发器，转换成真正的JASS代码。JASS是魔兽争霸3的脚本语言，用于控制地图的行为逻辑[^3]。完成学习后，你将能够打开触发器的&quot;自定义代码&quot;视图，看到每个设置对应的JASS语句。</p><h3 id="操作步骤-1" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤-1" aria-label="Permalink to “操作步骤”">​</a></h3><ol><li><p><strong>打开触发器代码视图</strong> — 在World Editor（世界编辑器）[^4]中，点击顶部菜单「触发器」→ 选择你想要查看的触发器 → 右键点击 → 选择「转换为自定义脚本」。这一步非常重要，很多新手会忽略这个选项！</p></li><li><p><strong>查看自动生成的JASS代码</strong> — 转换后，触发器下方会出现一个新的折叠区域，里面就是该触发器对应的JASS代码。例如，T触发中的&quot;单位死亡&quot;事件会转换为<code>TriggerRegisterUnitEvent</code>这样的JASS函数调用[^3]。</p></li><li><p><strong>对比理解对应关系</strong> — 打开代码后，你会看到类似这样的结构：</p><ul><li>事件部分：<code>TriggerRegisterUnitEvent(yourTrigger, yourUnit, EVENT_UNIT_DEATH)</code></li><li>条件部分：用<code>if then else</code>逻辑判断</li><li>动作部分：每个动作对应一个<code>BJ函数</code>或原生<code>Native函数</code></li></ul></li></ol><blockquote><p><strong>💡 新手提示</strong>：建议先转换一个简单的触发器来观察，比如只有&quot;单位死亡&quot;和&quot;显示提示文字&quot;两个步骤的触发器，这样更容易理解对应关系。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：新手经常混淆T触发中的&quot;条件&quot;（Condition）和&quot;动作&quot;（Action）。注意：条件是用来&quot;判断&quot;的，动作是真正&quot;执行&quot;的。在JASS中，条件通常写在函数开头作为判断，动作则按顺序执行。</p></blockquote><h3 id="小结-3" tabindex="-1">小结 <a class="header-anchor" href="#小结-3" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你应该能看到一个完整的JASS函数结构，包括<code>function Trig_你的触发器名_Conditions</code>（条件函数）和<code>function Trig_你的触发器名_Actions</code>（动作函数）。恭喜你，你已经迈出了从图形界面编辑走向代码编辑的第一步！</p><h2 id="常用jass函数与api速查" tabindex="-1">常用JASS函数与API速查 <a class="header-anchor" href="#常用jass函数与api速查" aria-label="Permalink to “常用JASS函数与API速查”">​</a></h2><p>本节将带你认识最常用的JASS函数，这些函数就像你的&quot;工具箱&quot;，让单位动起来、让玩家获得资源、让游戏按你的规则运行。学完本节后，你将能看懂大部分JASS代码，并写出简单的脚本。</p><h3 id="单位与玩家相关函数" tabindex="-1">单位与玩家相关函数 <a class="header-anchor" href="#单位与玩家相关函数" aria-label="Permalink to “单位与玩家相关函数”">​</a></h3><ol><li><strong>获取单位</strong> — 使用 <code>GetTriggerUnit()</code> 获取触发器中涉及的那个单位[^3]</li><li><strong>获取玩家</strong> — 使用 <code>GetOwningPlayer(unit)</code> 从单位身上提取它的主人（是1号玩家还是2号玩家）[^3]</li><li><strong>创建单位</strong> — 使用 <code>CreateUnitAtLoc(player, unitid, location, face)</code> 在地图某处生成一个新单位[^4]</li><li><strong>发送文字</strong> — 使用 <code>DisplayTextToPlayer(player, x, y, message)</code> 让指定玩家看到一行提示文字[^3]</li></ol><blockquote><p><strong>💡 新手提示</strong>：<code>player</code> 不是&quot;玩家名字&quot;，而是一个数字编号（0-23），0代表第一个玩家（红色），1代表第二个玩家（蓝色），以此类推。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：新手经常把 <code>GetTriggerUnit()</code> 和 <code>GetEnumUnit()</code> 搞混。前者是&quot;当前事件中的单位&quot;，后者是在循环中&quot;正在遍历的每一个单位&quot;。</p></blockquote><h3 id="游戏状态与计时器函数" tabindex="-1">游戏状态与计时器函数 <a class="header-anchor" href="#游戏状态与计时器函数" aria-label="Permalink to “游戏状态与计时器函数”">​</a></h3><ol><li><strong>获取游戏时间</strong> — 使用 <code>TimerGetElapsed(timer)</code> 读取计时器已经走了多久（单位：秒）</li><li><strong>设置计时器</strong> — 使用 <code>TimerStart(timer, timeout, periodic, handlerFunc)</code> 让计时器开始倒计时，结束后自动执行某个函数</li><li><strong>暂停游戏</strong> — 使用 <code>PauseGame(enable)</code> 可以暂停或恢复游戏进行</li><li><strong>修改资源</strong> — 使用 <code>SetPlayerState(player, PLAYER_STATE_GOLD, amount)</code> 直接修改玩家的金币数量</li></ol><blockquote><p><strong>💡 新手提示</strong>：计时器的 <code>periodic</code> 参数设为 <code>true</code> 代表&quot;重复触发&quot;（像闹钟一样循环响），设为 <code>false</code> 代表&quot;只响一次&quot;。</p></blockquote><h3 id="bj函数的作用与注意事项" tabindex="-1">BJ函数的作用与注意事项 <a class="header-anchor" href="#bj函数的作用与注意事项" aria-label="Permalink to “BJ函数的作用与注意事项”">​</a></h3><p>BJ函数是暴雪官方在JASS原生函数基础上封装的&quot;便利包装&quot;，让常用操作写起来更短[^3]。</p><ul><li><strong>为什么存在BJ函数？</strong> 比如原生创建单位需要写很多参数，而 <code>CreateUnitAtLoc</code> 帮你省去了很多步骤</li><li><strong>有什么风险？</strong> BJ函数内部会自动处理一些边界情况，但有时候会&quot;自作聪明&quot;，导致意料之外的行为</li><li><strong>什么时候用？</strong> 写触发器翻译代码时可以直接用，但做精密逻辑时建议查清具体行为</li></ul><blockquote><p><strong>⚠️ 常见错误</strong>：有些老教程直接写 <code>GetUnitsInRectAll(null)</code>，新手照搬后发现报错——正确写法是 <code>GetUnitsInRectAll(bj_mapInitialPlayableArea)</code> 或者自己定义一个区域变量。</p></blockquote><h3 id="小结-4" tabindex="-1">小结 <a class="header-anchor" href="#小结-4" aria-label="Permalink to “小结”">​</a></h3><p>完成以上学习后，你应该已经掌握了：</p><ul><li>如何获取和操作单位与玩家</li><li>如何使用计时器控制时间逻辑</li><li>如何区分JASS原生函数和BJ封装函数的用法</li></ul><p>你现在可以打开World Editor的触发器编辑器，尝试把GUI触发（图形界面触发器）翻译成JASS代码了！</p><h2 id="实践练习与学习资源推荐" tabindex="-1">实践练习与学习资源推荐 <a class="header-anchor" href="#实践练习与学习资源推荐" aria-label="Permalink to “实践练习与学习资源推荐”">​</a></h2><p>本节将为你推荐适合JASS新手的练习项目、优质学习资源，以及常见的调试方法。学完本节后，你将知道如何从简单的练习开始，逐步提升JASS编程能力。</p><h3 id="适合新手的简单练习项目" tabindex="-1">适合新手的简单练习项目 <a class="header-anchor" href="#适合新手的简单练习项目" aria-label="Permalink to “适合新手的简单练习项目”">​</a></h3><p>作为JASS的第一次动手实践，建议从以下简单的练习开始：</p><ol><li><p><strong>第一个练习：创建一个&quot;说 hello&quot;的触发器</strong>[^1]</p><ul><li>打开World Editor，在触发器编辑器中新建一个触发器</li><li>添加事件：<code>游戏 - 任意单位被攻击</code></li><li>添加动作：<code>游戏 - 显示标题信息给所有玩家，显示文本 &quot;Hello JASS!&quot;</code></li><li>测试地图，确认信息是否正确显示</li></ul></li><li><p><strong>第二个练习：简单的变量使用</strong></p><ul><li>创建一个整数变量 <code>counter</code></li><li>在触发器中设置 <code>Set counter = counter + 1</code></li><li>用 <code>DisplayTextMessage</code> 显示 <code>counter</code> 的当前值</li><li>这样你就学会了JASS中最基础的变量概念</li></ul></li><li><p><strong>第三个练习：观察生成的JASS代码</strong></p><ul><li>创建一个复杂的GUI触发器（在触发器编辑器中用图形界面操作）</li><li>右键点击触发器，选择&quot;转换为自定义代码&quot;</li><li>你会看到系统自动生成的JASS代码，这是学习JASS语法的好方法[^4]</li></ul></li></ol><blockquote><p><strong>💡 新手提示</strong>：每次练习后，尝试修改一点点代码，然后运行看效果。小的改动更容易理解，而且弄错了也容易找回。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：不要一上来就写很长的代码。新手最常见的错误是一次写太多，结果出问题也不知道哪里错。建议每次只改一个地方。</p></blockquote><h3 id="优质教程与社区资源" tabindex="-1">优质教程与社区资源 <a class="header-anchor" href="#优质教程与社区资源" aria-label="Permalink to “优质教程与社区资源”">​</a></h3><p><strong>推荐的学习资源</strong>：</p><ol><li><p><strong>Hiveworkshop</strong> (<a href="https://www.hiveworkshop.com" target="_blank" rel="noreferrer">https://www.hiveworkshop.com</a>)[^1] — 这是全球最大的 Warcraft III 资源社区，有大量的JASS教程和示例代码，即使是英文内容也有代码可以参考学习。</p></li><li><p><strong>World Editor自带帮助</strong> — 在触发器编辑器中按F1，可以看到很多内置函数的说明。这是学习JASS函数最权威的中文参考资料。</p></li><li><p><strong>KK平台官方教程</strong> — 在KK地图编辑器内置的新手引导中，有专门针对JASS基础的视频讲解。</p></li></ol><blockquote><p><strong>💡 新手提示</strong>：遇到不懂的函数时，先在World Editor中搜索该函数，然后查看它的参数说明和示例，这是最好的学习方式。</p></blockquote><h3 id="常见错误与调试技巧" tabindex="-1">常见错误与调试技巧 <a class="header-anchor" href="#常见错误与调试技巧" aria-label="Permalink to “常见错误与调试技巧”">​</a></h3><p><strong>JASS新手最容易犯的错误</strong>：</p><ol><li><p><strong>大小写错误</strong> — JASS区分大小写，<code>Set</code> 和 <code>set</code> 是完全不同的概念[^4]</p></li><li><p><strong>漏写分号</strong> — 每一行JASS代码末尾必须以分号 <code>;</code> 结束，漏写会导致整段代码报错</p></li><li><p><strong>括号不匹配</strong> — 打开的括号必须正确关闭，可以用代码编辑器的自动高亮功能检查</p></li></ol><p><strong>调试小技巧</strong>：</p><ul><li>在关键位置加入 <code>call DisplayTextToForce(GetPlayersAll(), &quot;debug message&quot;)</code> 来输出调试信息</li><li>使用 BJDebugMsg 可以显示变量值</li><li>善用World Editor的&quot;测试地图&quot;功能，错误信息会显示在屏幕上方</li></ul><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手看到报错信息就慌了。其实 Warcraft 的错误提示会告诉你是哪一行出错，耐心查看消息内容，大部分问题都能自己解决。</p></blockquote><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to “参考来源”">​</a></h2><p>[^1]: <a href="https://www.hiveworkshop.com/threads/ever-wanted-to-run-jass-scripts-outside-of-war3.266101/" target="_blank" rel="noreferrer">Ever wanted to run jass scripts outside of war3? | HIVE</a> — accessed 2026-05-21 [^2]: <a href="https://deepwiki.com/qq1792569310/demodemodemodemo/2.3-jass-native-hooking" target="_blank" rel="noreferrer">JASS Native Hooking | DeepWiki</a> — accessed 2026-05-21 [^3]: <a href="https://3gstudent.github.io/backup-3gstudent.github.io/War3%E5%9C%B0%E5%9B%BE-%E6%BC%8F%E6%B4%9E-%E5%88%86%E6%9E%90%E4%BB%8B%E7%BB%8D/" target="_blank" rel="noreferrer">War3地图&quot;漏洞&quot;分析介绍 – 3gstudent</a> — accessed 2026-05-21 [^4]: <a href="https://nextgenupdate.com/forums/pc-amp-steam-gaming/221496-basic-tutorialthe-warcraft-three-world-editor-1.html" target="_blank" rel="noreferrer">[Basic Tutorial] The Warcraft Three World Editor - NextGenUpdate</a> — accessed 2026-05-21 [^5]: <a href="https://www.3ice.hu/blog/protect-warcraft-maps/" target="_blank" rel="noreferrer">Protecting Warcraft 3 maps - Vexorian&#39;s Map Optimizer and other...</a> — accessed 2026-05-21</p>`,86)])])}const g=e(s,[["render",i]]);export{h as __pageData,g as default};
